INSERT INTO `his_config_info` VALUES (2, 11, 'model_router', 'CHAT_RAG', '', 'enabled: true\nstrategy: semantic\nsemantic:\n  analyzer:\n    model: Qwen-3-30B\n    timeoutMs: 3000\n    totalTimeoutMs: 3000\n    endpoint: \"http://172.16.254.5:32326/v1/chat/completions\"\n    apiToken: \"sk-38DYeMAdOUdAGb1a14E0348c3fCd492d8e5fAaC24505FbF1\"\n    # 可选高级项：\n    # totalTimeoutMs: 5000\n    # maxInputBytes: 8192\n    # promptTemplate: \"\"   # 自定义分类 Prompt，不配置则使用内置默认\n    # analysisLabels: [\"simple_request\", \"planning_request\", \"code_modification\"]\n    # dynamicMetrics:\n    #   enabled: false\n    #   redisPrefix: \"ai_router:metrics:\"\n    #   metrics: [\"error_rate\", \"p99\", \"circuit\"]\n  routing:\n    candidates:\n    - enabled: true\n      modelName: \"MiniMax-M2.1\"\n      scores:\n        code_modification: 10\n        planning_request: 0\n        simple_request: 8\n    - enabled: true\n      modelName: \"MiniMax-M2.1\"\n      scores:\n        code_modification: 0\n        planning_request: 0\n        simple_request: 5\n    minScore: 1\n    fallbackModelName: \"MiniMax-M2.1\"\n  ruleEngine:\n    enabled: true\n    inlineRules: []', '627927a5ed46b2c06b081c92f41bd24d', '2026-01-13 13:10:51', '2026-01-13 21:12:53', 'costrict', '10.200.101.6', 'U', '8e96a146-756b-4d0c-888c-382fd792f55b', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"costrict\"}');
